@code {
    [Parameter] public int Id { get; set; }
    private Invoice? invoice;
    private InvoiceItem newItem = new() { Quantity = 1 };
    private Payment newPayment = new();

    protected override async Task OnInitializedAsync() => await LoadInvoice();

    private async Task LoadInvoice()
    {
        invoice = await Db.Invoices
            .Include(i => i.Owner)
            .Include(i => i.Items)
            .Include(i => i.Payments)
            .FirstOrDefaultAsync(i => i.Id == Id);
    }

    private async Task AddItem()
    {
        newItem.InvoiceId = Id;
        newItem.Amount = newItem.Quantity * newItem.UnitPrice;
        Db.InvoiceItems.Add(newItem);
        invoice!.TotalAmount = invoice.Items.Sum(i => i.Amount) + newItem.Amount;
        await Db.SaveChangesAsync();
        newItem = new InvoiceItem { Quantity = 1 };
        await LoadInvoice();
    }

    private async Task ProcessPayment()
    {
        newPayment.InvoiceId = Id;
        newPayment.PaymentDate = DateTime.UtcNow;
        Db.Payments.Add(newPayment);
        var totalPaid = invoice!.Payments.Sum(p => p.Amount) + newPayment.Amount;
        if (totalPaid >= invoice.TotalAmount)
            invoice.Status = InvoiceStatus.Paid;
        await Db.SaveChangesAsync();
        newPayment = new Payment();
        await LoadInvoice();
    }

    private string GetStatusColor(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Pending => "warning",
        InvoiceStatus.Paid => "success",
        InvoiceStatus.Overdue => "danger",
        _ => "secondary"
    };
}
