        appointments = await Db.Appointments.Include(a => a.Pet).Where(a => a.Status == AppointmentStatus.Completed).OrderByDescending(a => a.AppointmentDate).Take(20).ToListAsync();
    }

    private void AddLineItem() => lineItems.Add(new InvoiceItem { Quantity = 1 });

    private void RecalcItems()
    {
        foreach (var item in lineItems)
            item.Amount = item.Quantity * item.UnitPrice;
    }

    private async Task Save()
    {
        RecalcItems();
        invoice.InvoiceDate = DateTime.UtcNow;
        invoice.TotalAmount = lineItems.Sum(i => i.Amount);
        Db.Invoices.Add(invoice);
        await Db.SaveChangesAsync();
        foreach (var item in lineItems)
        {
            item.InvoiceId = invoice.Id;
            Db.InvoiceItems.Add(item);
        }
        await Db.SaveChangesAsync();
        Nav.NavigateTo($"/billing/{invoice.Id}");
    }
}
