```razor
@page "/appointments"
@attribute [Authorize]
@rendermode InteractiveServer
@inject ApplicationDbContext Db
@inject NavigationManager Nav
@using Microsoft.EntityFrameworkCore

<PageTitle>Appointments</PageTitle>

<div class="d-flex justify-content-between align-items-center mb-4">
    <h1>Appointments</h1>
    <a href="/appointments/new" class="btn btn-primary">New Appointment</a>
</div>

<div class="d-flex justify-content-between align-items-center mb-3">
    <button class="btn btn-outline-secondary" @onclick="PreviousWeek">&laquo; Previous</button>
    <h4>@weekStart.ToString("MMM dd") - @weekStart.AddDays(6).ToString("MMM dd, yyyy")</h4>
    <button class="btn btn-outline-secondary" @onclick="NextWeek">Next &raquo;</button>
</div>

<div class="table-responsive">
    <table class="table table-bordered" style="table-layout: fixed;">
        <thead>
            <tr>
                <th style="width: 80px;">Time</th>
                @for (int d = 0; d < 7; d++)
                {
                    var day = weekStart.AddDays(d);
                    <th class="text-center @(day.Date == DateTime.UtcNow.Date ? "table-active" : "")">
                        @day.ToString("ddd MM/dd")
                    </th>
                }
            </tr>
        </thead>
        <tbody>
            @for (int hour = 8; hour < 18; hour++)
            {
                @for (int min = 0; min < 60; min += 30)
                {
                    <tr>
                        <td class="text-muted small">@(new TimeOnly(hour, min).ToString("h:mm tt"))</td>
                        @for (int d = 0; d < 7; d++)
                        {
                            var slotDate = weekStart.AddDays(d).AddHours(hour).AddMinutes(min);
                            var apt = GetAppointmentAt(slotDate);
                            if (apt != null)
                            {
                                <td class="p-1" style="cursor:pointer;" @onclick="() => Nav.NavigateTo($@"/appointments/{apt.Id}/edit")">
                                    <div class="rounded p-1 text-white small bg-@GetStatusColor(apt.Status)">
                                        <strong>@apt.Pet.Name</strong><br/>
                                        <span>@apt.Reason</span>
                                    </div>
                                </td>
                            }
                            else
                            {
                                var slot = slotDate;
                                <td class="p-1 slot-available" style="cursor:pointer;" @onclick="() => CreateAtSlot(slot)">
                                </td>
                            }
                        }
                    </tr>
                }
            }
        </tbody>
    </table>
</div>

@code {
    private DateTime weekStart;
    private List<Appointment> appointments = new();

    protected override async Task OnInitializedAsync()
    {
        weekStart = DateTime.UtcNow.Date.AddDays(-(int)DateTime.UtcNow.DayOfWeek + 1);
        await LoadAppointments();
    }

    private async Task LoadAppointments()
    {
        var weekEnd = weekStart.AddDays(7);
        appointments = await Db.Appointments
            .Include(a => a.Pet)
            .Where(a => a.AppointmentDate >= weekStart && a.AppointmentDate < weekEnd)
            .ToListAsync();
    }

    private Appointment? GetAppointmentAt(DateTime slot)
    {
        return appointments.FirstOrDefault(a => a.AppointmentDate == slot);
    }

    private async Task PreviousWeek()
    {
        weekStart = weekStart.AddDays(-7);
        await LoadAppointments();
    }

    private async Task NextWeek()
    {
        weekStart = weekStart.AddDays(7);
        await LoadAppointments();
    }

    private void CreateAtSlot(DateTime slot)
    {
        Nav.NavigateTo($"/appointments/new?date={slot:yyyy-MM-ddTHH:mm}");
    }

    private string GetStatusColor(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "primary",
        AppointmentStatus.Completed => "success",
        AppointmentStatus.Cancelled => "danger",
        _ => "secondary"
    };
}
