    <div class="row">
        <div class="col-md-6">
            <div class="mb-3">
                <label class="form-label">Pet</label>
                <InputSelect class="form-select" @bind-Value="appointment.PetId">
                    <option value="0">-- Select Pet --</option>
                    @foreach (var pet in pets)
                    {
                        <option value="@pet.Id">@pet.Name (@pet.Owner.FullName)</option>
                    }
                </InputSelect>
            </div>
            <div class="mb-3">
                <label class="form-label">Date & Time</label>
                <InputDate class="form-control" Type="InputDateType.DateTimeLocal" @bind-Value="appointment.AppointmentDate" />
            </div>
            <div class="mb-3">
                <label class="form-label">Duration (minutes)</label>
                <InputNumber class="form-control" @bind-Value="appointment.DurationMinutes" />
            </div>
        </div>
        <div class="col-md-6">
            <div class="mb-3">
                <label class="form-label">Reason</label>
                <InputText class="form-control" @bind-Value="appointment.Reason" />
            </div>
            <div class="mb-3">
                <label class="form-label">Veterinarian</label>
                <InputText class="form-control" @bind-Value="appointment.Veterinarian" />
            </div>
            <div class="mb-3">
                <label class="form-label">Status</label>
                <InputSelect class="form-select" @bind-Value="appointment.Status">
                    @foreach (var s in Enum.GetValues<AppointmentStatus>())
                    {
                        <option value="@s">@s</option>
                    }
                </InputSelect>
            </div>
            <div class="mb-3">
                <label class="form-label">Notes</label>
                <InputTextArea class="form-control" @bind-Value="appointment.Notes" />
            </div>
        </div>
    </div>

    <button type="submit" class="btn btn-primary">@(Id == null ? "Create" : "Save")</button>
    <a href="/appointments" class="btn btn-outline-secondary ms-2">Cancel</a>
</EditForm>

@code {
    [Parameter] public int? Id { get; set; }
    [SupplyParameterFromQuery] public string? Date { get; set; }
    private Appointment appointment = new() { AppointmentDate = DateTime.UtcNow, DurationMinutes = 30 };
    private List<Pet> pets = new();
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        pets = await Db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
        if (Id != null)
        {
            var existing = await Db.Appointments.FindAsync(Id.Value);
            if (existing != null) appointment = existing;
        }
        else if (!string.IsNullOrEmpty(Date) && DateTime.TryParse(Date, out var parsedDate))
        {
            appointment.AppointmentDate = parsedDate;
        }
    }

    private async Task Save()
    {
        // Validate no double-booking
        var endTime = appointment.AppointmentDate.AddMinutes(appointment.DurationMinutes);
        var conflict = await Db.Appointments
            .Where(a => a.Id != (Id ?? 0) && a.Status != AppointmentStatus.Cancelled)
            .Where(a => a.Veterinarian == appointment.Veterinarian)
            .Where(a => a.AppointmentDate < endTime && a.AppointmentDate.AddMinutes(a.DurationMinutes) > appointment.AppointmentDate)
            .AnyAsync();

        if (conflict)
        {
            errorMessage = "This time slot conflicts with another appointment for the same veterinarian.";
            return;
        }

        if (Id == null)
        {
            Db.Appointments.Add(appointment);
        }
        else
        {
            Db.Appointments.Update(appointment);
        }
        await Db.SaveChangesAsync();
        Nav.NavigateTo("/appointments");
    }
}
