            <a href="/patients/@Id/edit" class="btn btn-outline-secondary">Edit</a>
            <a href="/patients" class="btn btn-outline-primary">Back to List</a>
        </div>
    </div>

    <div class="row mb-4">
        <div class="col-md-6">
            <div class="card">
                <div class="card-header"><h5>Pet Information</h5></div>
                <div class="card-body">
                    <dl class="row mb-0">
                        <dt class="col-sm-4">Species</dt><dd class="col-sm-8"><span class="badge bg-secondary">@pet.Species</span></dd>
