    protected override async Task OnInitializedAsync()
    {
        invoices = await Db.Invoices.Include(i => i.Owner).OrderByDescending(i => i.InvoiceDate).ToListAsync();
        ApplyFilter();
    }

    private void SetFilter(string f) { filter = f; ApplyFilter(); }

    private void ApplyFilter()
    {
        filteredInvoices = filter switch
        {
            "Pending" => invoices?.Where(i => i.Status == InvoiceStatus.Pending).ToList(),
            "Paid" => invoices?.Where(i => i.Status == InvoiceStatus.Paid).ToList(),
            "Overdue" => invoices?.Where(i => i.Status == InvoiceStatus.Overdue).ToList(),
            _ => invoices
        };
