                    <div class="col-md-4"><InputText class="form-control" placeholder="Description" @bind-Value="newItem.Description" /></div>
                    <div class="col-md-2"><InputNumber class="form-control" placeholder="Qty" @bind-Value="newItem.Quantity" /></div>
                    <div class="col-md-2"><InputNumber class="form-control" placeholder="Unit Price" @bind-Value="newItem.UnitPrice" /></div>
                    <div class="col-md-2"><button type="submit" class="btn btn-success">Add</button></div>
                </div>
            </EditForm>
        </div>
    </div>

    <div class="card mb-4">
        <div class="card-header"><h5>Payments</h5></div>
        <div class="card-body">
            @if (invoice.Payments.Any())
            {
                <table class="table">
                    <thead><tr><th>Date</th><th>Amount</th><th>Method</th><th>Reference</th></tr></thead>
                    <tbody>
                        @foreach (var p in invoice.Payments.OrderByDescending(p => p.PaymentDate))
                        {
                            <tr>
                                <td>@p.PaymentDate.ToString("MMM dd, yyyy")</td>
                                <td>$@p.Amount.ToString("N2")</td>
                                <td>@p.Method</td>
                                <td>@p.Reference</td>
                            </tr>
                        }
                    </tbody>
                </table>
            }

            @if (invoice.Status != InvoiceStatus.Paid)
            {
                <h6>Process Payment</h6>
                <EditForm Model="newPayment" OnValidSubmit="ProcessPayment" FormName="processPayment">
                    <div class="row g-2 align-items-end">
                        <div class="col-md-3"><InputNumber class="form-control" placeholder="Amount" @bind-Value="newPayment.Amount" /></div>
                        <div class="col-md-3">
                            <InputSelect class="form-select" @bind-Value="newPayment.Method">
                                @foreach (var m in Enum.GetValues<PaymentMethod>())
                                {
                                    <option value="@m">@m</option>
                                }
                            </InputSelect>
                        </div>
                        <div class="col-md-3"><InputText class="form-control" placeholder="Reference" @bind-Value="newPayment.Reference" /></div>
                        <div class="col-md-3"><button type="submit" class="btn btn-primary">Record Payment</button></div>
                    </div>
                </EditForm>
            }
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }
    private Invoice? invoice;
    private InvoiceItem newItem = new() { Quantity = 1 };
    private Payment newPayment = new();

    protected override async Task OnInitializedAsync() => await LoadInvoice();

    private async Task LoadInvoice()
    {
        invoice = await Db.Invoices
            .Include(i => i.Owner)
            .Include(i => i.Items)
            .Include(i => i.Payments)
            .FirstOrDefaultAsync(i => i.Id == Id);
    }

    private async Task AddItem()
    {
        newItem.InvoiceId = Id;
        newItem.Amount = newItem.Quantity * newItem.UnitPrice;
        Db.InvoiceItems.Add(newItem);
        invoice!.TotalAmount = invoice.Items.Sum(i => i.Amount) + newItem.Amount;
        await Db.SaveChangesAsync();
        newItem = new InvoiceItem { Quantity = 1 };
        await LoadInvoice();
    }

    private async Task ProcessPayment()
    {
        newPayment.InvoiceId = Id;
        newPayment.PaymentDate = DateTime.UtcNow;
        Db.Payments.Add(newPayment);
        var totalPaid = invoice!.Payments.Sum(p => p.Amount) + newPayment.Amount;
        if (totalPaid >= invoice.TotalAmount)
            invoice.Status = InvoiceStatus.Paid;
        await Db.SaveChangesAsync();
        newPayment = new Payment();
        await LoadInvoice();
    }

    private string GetStatusColor(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Pending => "warning",
        InvoiceStatus.Paid => "success",
        InvoiceStatus.Overdue => "danger",
        _ => "secondary"
    };
}

@page "/billing/new"
@attribute [Authorize]
@rendermode InteractiveServer
@inject ApplicationDbContext Db
@inject NavigationManager Nav
@using Microsoft.EntityFrameworkCore

<PageTitle>New Invoice</PageTitle>

<h1>New Invoice</h1>

<EditForm Model="invoice" OnValidSubmit="Save" FormName="invoiceForm">
    <DataAnnotationsValidator />

    <div class="row">
        <div class="col-md-6">
            <div class="mb-3">
                <label class="form-label">Owner</label>
                <InputSelect class="form-select" @bind-Value="invoice.OwnerId">
                    <option value="0">-- Select Owner --</option>
                    @foreach (var owner in owners)
                    {
                        <option value="@owner.Id">@owner.FullName</option>
                    }
                </InputSelect>
            </div>
            <div class="mb-3">
                <label class="form-label">Appointment (optional)</label>
                <InputSelect class="form-select" @bind-Value="invoice.AppointmentId">
                    <option value="">-- None --</option>
                    @foreach (var apt in appointments)
                    {
                        <option value="@apt.Id">@apt.AppointmentDate.ToString("MMM dd") - @apt.Pet.Name - @apt.Reason</option>
                    }
                </InputSelect>
            </div>
            <div class="mb-3">
                <label class="form-label">Due Date</label>
                <InputDate class="form-control" @bind-Value="invoice.DueDate" />
            </div>
            <div class="mb-3">
                <label class="form-label">Notes</label>
                <InputTextArea class="form-control" @bind-Value="invoice.Notes" />
            </div>
        </div>
        <div class="col-md-6">
            <div class="card">
                <div class="card-header d-flex justify-content-between"><h5>Line Items</h5><span class="fw-bold">Total: $@lineItems.Sum(i => i.Amount).ToString("N2")</span></div>
                <div class="card-body">
                    @foreach (var item in lineItems)
                    {
                        <div class="row g-2 mb-2">
                            <div class="col-5"><input class="form-control" @bind="item.Description" placeholder="Description" /></div>
                            <div class="col-2"><input type="number" class="form-control" @bind="item.Quantity" @bind:after="RecalcItems" /></div>
                            <div class="col-3"><input type="number" step="0.01" class="form-control" @bind="item.UnitPrice" @bind:after="RecalcItems" /></div>
                            <div class="col-2"><button type="button" class="btn btn-sm btn-danger" @onclick="() => lineItems.Remove(item)">X</button></div>
                        </div>
                    }
                    <button type="button" class="btn btn-sm btn-outline-success" @onclick="AddLineItem">+ Add Item</button>
                </div>
            </div>
        </div>
    </div>

    <div class="mt-3">
        <button type="submit" class="btn btn-primary">Create Invoice</button>
        <a href="/billing" class="btn btn-outline-secondary ms-2">Cancel</a>
    </div>
</EditForm>

@code {
    private Invoice invoice = new() { DueDate = DateTime.UtcNow.AddDays(30) };
    private List<Owner> owners = new();
    private List<Appointment> appointments = new();
    private List<InvoiceItem> lineItems = new() { new InvoiceItem { Quantity = 1 } };

    protected override async Task OnInitializedAsync()
    {
        owners = await Db.Owners.OrderBy(o => o.LastName).ToListAsync();
        appointments = await Db.Appointments.Include(a => a.Pet).Where(a => a.Status == AppointmentStatus.Completed).OrderByDescending(a => a.AppointmentDate).Take(20).ToListAsync();
    }

    private void AddLineItem() => lineItems.Add(new InvoiceItem { Quantity = 1 });

    private void RecalcItems()
    {
        foreach (var item in lineItems)
            item.Amount = item.Quantity * item.UnitPrice;
    }

    private async Task Save()
    {
        RecalcItems();
        invoice.InvoiceDate = DateTime.UtcNow;
        invoice.TotalAmount = lineItems.Sum(i => i.Amount);
        Db.Invoices.Add(invoice);
        await Db.SaveChangesAsync();
        foreach (var item in lineItems)
        {
            item.InvoiceId = invoice.Id;
            Db.InvoiceItems.Add(item);
        }
        await Db.SaveChangesAsync();
        Nav.NavigateTo($"/billing/{invoice.Id}");
    }
}

