@page "/"
@attribute [Authorize]
@rendermode InteractiveServer
@inject ApplicationDbContext Db
@using Microsoft.EntityFrameworkCore

<PageTitle>VetClinic Dashboard</PageTitle>

<h1 class="mb-4">Dashboard</h1>

<div class="row mb-4">
