        <div class="card text-white bg-primary">
            <div class="card-body">
                <h5 class="card-title">Today's Appointments</h5>
                <h2>@todayAppointments</h2>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-white bg-warning">
            <div class="card-body">
                <h5 class="card-title">Pending Invoices</h5>
                <h2>@pendingInvoices</h2>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-white bg-success">
            <div class="card-body">
                <h5 class="card-title">Total Patients</h5>
                <h2>@totalPatients</h2>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-white bg-info">
            <div class="card-body">
                <h5 class="card-title">Total Owners</h5>
                <h2>@totalOwners</h2>
            </div>
        </div>
    </div>
</div>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="card">
            <div class="card-header"><h5>Quick Actions</h5></div>
            <div class="card-body">
                <a href="/patients/new" class="btn btn-primary me-2">New Patient</a>
                <a href="/appointments/new" class="btn btn-success me-2">New Appointment</a>
                <a href="/billing/new" class="btn btn-warning me-2">New Invoice</a>
            </div>
        </div>
    </div>
    <div class="col-md-6">
        <div class="card">
            <div class="card-header"><h5>Recent Patients</h5></div>
            <div class="card-body">
                @if (recentPets.Any())
                {
                    <ul class="list-group list-group-flush">
                        @foreach (var pet in recentPets)
                        {
                            <li class="list-group-item d-flex justify-content-between">
                                <span><a href="/patients/@pet.Id">@pet.Name</a> (@pet.Species)</span>
                                <span class="text-muted">Owner: @pet.Owner.FullName</span>
                            </li>
                        }
                    </ul>
                }
                else
                {
                    <p class="text-muted">No patients yet.</p>
                }
            </div>
        </div>
    </div>
</div>

<div class="row">
    <div class="col-md-12">
        <div class="card">
            <div class="card-header"><h5>Today's Schedule</h5></div>
            <div class="card-body">
                @if (todaySchedule.Any())
                {
                    <table class="table">
                        <thead><tr><th>Time</th><th>Pet</th><th>Owner</th><th>Reason</th><th>Vet</th><th>Status</th></tr></thead>
                        <tbody>
                            @foreach (var apt in todaySchedule)
                            {
                                <tr>
                                    <td>@apt.AppointmentDate.ToString("h:mm tt")</td>
                                    <td>@apt.Pet.Name</td>
                                    <td>@apt.Pet.Owner.FullName</td>
                                    <td>@apt.Reason</td>
                                    <td>@apt.Veterinarian</td>
                                    <td><span class="badge bg-@GetStatusColor(apt.Status)">@apt.Status</span></td>
                                </tr>
                            }
                        </tbody>
                    </table>
                }
                else
                {
                    <p class="text-muted">No appointments scheduled for today.</p>
                }
            </div>
        </div>
    </div>
</div>

@code {
    private int todayAppointments;
    private int pendingInvoices;
    private int totalPatients;
    private int totalOwners;
    private List<Pet> recentPets = new();
    private List<Appointment> todaySchedule = new();

    protected override async Task OnInitializedAsync()
    {
        var today = DateTime.UtcNow.Date;
        todayAppointments = await Db.Appointments.CountAsync(a => a.AppointmentDate.Date == today && a.Status == AppointmentStatus.Scheduled);
        pendingInvoices = await Db.Invoices.CountAsync(i => i.Status == InvoiceStatus.Pending || i.Status == InvoiceStatus.Overdue);
        totalPatients = await Db.Pets.CountAsync();
        totalOwners = await Db.Owners.CountAsync();
        recentPets = await Db.Pets.Include(p => p.Owner).OrderByDescending(p => p.CreatedAt).Take(5).ToListAsync();
        todaySchedule = await Db.Appointments.Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.AppointmentDate.Date == today)
            .OrderBy(a => a.AppointmentDate)
            .ToListAsync();
    }

    private string GetStatusColor(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "primary",
        AppointmentStatus.Completed => "success",
        AppointmentStatus.Cancelled => "danger",
        _ => "secondary"
    };
}

