@using Microsoft.EntityFrameworkCore

<PageTitle>Patients</PageTitle>

<div class="d-flex justify-content-between align-items-center mb-4">
    <h1>Patients</h1>
    <a href="/patients/new" class="btn btn-primary">Add New Patient</a>
</div>

<div class="mb-3">
    <input type="text" class="form-control" placeholder="Search by name, breed, or owner..." @bind="searchTerm" @bind:event="oninput" @bind:after="Search" />
</div>

@if (pets == null)
{
    <p>Loading...</p>
}
else if (!pets.Any())
{
    <p class="text-muted">No patients found.</p>
}
else
{
    <div class="table-responsive">
        <table class="table table-hover">
            <thead>
                <tr><th>Name</th><th>Species</th><th>Breed</th><th>Owner</th><th>Weight</th><th>Actions</th></tr>
            </thead>
            <tbody>
                @foreach (var pet in pets)
                {
                    <tr>
                        <td><a href="/patients/@pet.Id">@pet.Name</a></td>
                        <td><span class="badge bg-secondary">@pet.Species</span></td>
                        <td>@pet.Breed</td>
                        <td>@pet.Owner.FullName</td>
                        <td>@pet.Weight kg</td>
                        <td>
                            <a href="/patients/@pet.Id" class="btn btn-sm btn-outline-primary">View</a>
                            <a href="/patients/@pet.Id/edit" class="btn btn-sm btn-outline-secondary">Edit</a>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    private List<Pet>? pets;
    private string searchTerm = "";

    protected override async Task OnInitializedAsync()
    {
        await LoadPets();
    }

    private async Task LoadPets()
    {
        var query = Db.Pets.Include(p => p.Owner).AsQueryable();
        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.ToLower();
            query = query.Where(p => p.Name.ToLower().Contains(term) ||
                                     p.Breed.ToLower().Contains(term) ||
                                     p.Owner.FirstName.ToLower().Contains(term) ||
                                     p.Owner.LastName.ToLower().Contains(term));
        }
        pets = await query.OrderBy(p => p.Name).ToListAsync();
    }

    private async Task Search() => await LoadPets();
}

