</EditForm>

@code {
    [Parameter] public int? Id { get; set; }
    [SupplyParameterFromQuery] public string? Date { get; set; }
    private Appointment appointment = new() { AppointmentDate = DateTime.UtcNow, DurationMinutes = 30 };
    private List<Pet> pets = new();
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        pets = await Db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
        if (Id != null)
        {
            var existing = await Db.Appointments.FindAsync(Id.Value);
            if (existing != null) appointment = existing;
        }
        else if (!string.IsNullOrEmpty(Date) && DateTime.TryParse(Date, out var parsedDate))
        {
            appointment.AppointmentDate = parsedDate;
        }
    }

    private async Task Save()
    {
        // Validate no double-booking
        var endTime = appointment.AppointmentDate.AddMinutes(appointment.DurationMinutes);
        var conflict = await Db.Appointments
            .Where(a => a.Id != (Id ?? 0) && a.Status != AppointmentStatus.Cancelled)
            .Where(a => a.Veterinarian == appointment.Veterinarian)
            .Where(a => a.AppointmentDate < endTime && a.AppointmentDate.AddMinutes(a.DurationMinutes) > appointment.AppointmentDate)
            .AnyAsync();

        if (conflict)
        {
            errorMessage = "This time slot conflicts with another appointment for the same veterinarian.";
            return;
        }

        if (Id == null)
        {
            Db.Appointments.Add(appointment);
        }
        else
        {
            Db.Appointments.Update(appointment);
        }
        await Db.SaveChangesAsync();
        Nav.NavigateTo("/appointments");
    }
}

