                            <div class="col-3"><input type="number" step="0.01" class="form-control" @bind="item.UnitPrice" @bind:after="RecalcItems" /></div>
                            <div class="col-2"><button type="button" class="btn btn-sm btn-danger" @onclick="() => lineItems.Remove(item)">X</button></div>
                        </div>
